            raise KeyError("Unknown SKU")
        if self.available(sku) < qty:
            return False
        self.reservations.setdefault(sku, 0)
        self.reservations[sku] += qty
        return True

    def release(self, sku, qty):
        if sku not in self.reservations:
            return
        self.reservations[sku] = max(0, self.reservations[sku] - qty)

    def ship(self, sku, qty):
        if sku not in self.reservations:
            return False
        if self.reservations[sku] < qty:
            return False
        self.reservations[sku] -= qty
        self.stock[sku] -= qty
